// ── Parse Internshala HTML ──────────────────────────────
const cheerio = require('cheerio');
const html = $input.first().json.data || '';
const $ = cheerio.load(html);
const jobs = [];

$('.internship_meta').each((i, el) => {
  const title   = $(el).find('.profile').text().trim();
  const company = $(el).find('.company_name').text().trim();
  const link    = 'https://internshala.com' + ($(el).find('a.view_detail_button').attr('href') || '');
  const stipend = $(el).find('.stipend').text().trim();
  const location = $(el).find('.location_link').text().trim();
  const jobId   = 'internshala_' + Buffer.from(link).toString('base64').slice(0, 12);

  if (title) {
    jobs.push({ jobId, title, company, link, stipend, location, source: 'Internshala' });
  }
});

return jobs.map(j => ({ json: j }));

// ── Parse RemoteOK JSON API ─────────────────────────────
// RemoteOK returns a JSON array; first element is a legal notice object — skip it.
const raw = $input.first().json;
const items = Array.isArray(raw) ? raw.slice(1) : [];

const INTERN_KEYWORDS = ['intern', 'internship', 'junior', 'entry', 'fresher', 'trainee', 'graduate'];

return items
  .filter(r => {
    const text = `${r.position} ${(r.tags || []).join(' ')}`.toLowerCase();
    return INTERN_KEYWORDS.some(k => text.includes(k));
  })
  .map(r => ({
    json: {
      jobId:    'remoteok_' + r.id,
      title:    r.position,
      company:  r.company,
      link:     r.url,
      stipend:  r.salary_min ? `$${r.salary_min}–$${r.salary_max}/yr` : 'Remote · See listing',
      location: 'Remote Worldwide',
      source:   'RemoteOK'
    }
  }));

// ── Parse Adzuna JSON API response ──────────────────────
const body = $input.first().json;
const results = body.results || [];

return results.map(r => ({
  json: {
    jobId:    'adzuna_' + r.id,
    title:    r.title,
    company:  r.company?.display_name || 'Unknown',
    link:     r.redirect_url,
    stipend:  r.salary_min ? `₹${Math.round(r.salary_min / 12).toLocaleString()}/mo` : 'Not listed',
    location: r.location?.display_name || '',
    source:   'Adzuna'
  }
}));

// ── Keyword & Quality Filter ─────────────────────────────
const KEYWORDS = [
  'python', 'machine learning', 'ml', 'data science',
  'backend', 'django', 'flask', 'fastapi', 'node', 'react',
  'ai', 'nlp', 'deep learning', 'computer vision', 'remote'
];

const EXCLUDE = ['senior', 'lead', 'manager', 'director', '5+ years', '7+ years'];

const matched = [];

for (const item of $input.all()) {
  const j = item.json;
  const text = `${j.title} ${j.company} ${j.location}`.toLowerCase();

  const hasKeyword = KEYWORDS.some(k => text.includes(k));
  const isExcluded = EXCLUDE.some(e => text.includes(e));

  if (hasKeyword && !isExcluded) {
    matched.push({ json: j });
  }
}

return matched;

// ── Deduplication: remove jobs already logged ─────────────
const allJobs  = $input.all().filter(i => i.json.jobId);
const seenRows = $input.all().filter(i => i.json.job_id);

const seenIds = new Set(seenRows.map(r => r.json.job_id));

const newJobs = allJobs.filter(j => !seenIds.has(j.json.jobId));

if (newJobs.length === 0) {
  return [{ json: { _noNewJobs: true } }];
}

return newJobs;

// ── Build Email HTML & Slack Block ───────────────────────
const jobs = $input.all().map(i => i.json);

// HTML email body
const rows = jobs.map(j => `
  <tr>
    <td style="padding:10px 8px;border-bottom:1px solid #eee">
      <a href="${j.link}" style="color:#4f46e5;font-weight:600;text-decoration:none">${j.title}</a><br>
      <span style="color:#555;font-size:13px">${j.company} · ${j.location}</span>
    </td>
    <td style="padding:10px 8px;border-bottom:1px solid #eee;color:#10b981;font-weight:500">${j.stipend}</td>
    <td style="padding:10px 8px;border-bottom:1px solid #eee;color:#6b7280;font-size:12px">${j.source}</td>
  </tr>
`).join('');

const emailHtml = `
<div style="font-family:Arial,sans-serif;max-width:640px;margin:auto">
  <h2 style="color:#4f46e5">🎯 InternHunt — ${jobs.length} new internship${jobs.length > 1 ? 's' : ''} found</h2>
  <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse">
    <thead>
      <tr style="background:#f5f3ff">
        <th style="text-align:left;padding:10px 8px;color:#4f46e5">Role</th>
        <th style="text-align:left;padding:10px 8px;color:#4f46e5">Stipend</th>
        <th style="text-align:left;padding:10px 8px;color:#4f46e5">Source</th>
      </tr>
    </thead>
    <tbody>${rows}</tbody>
  </table>
  <p style="color:#9ca3af;font-size:12px;margin-top:20px">Powered by InternHunt · n8n workflow</p>
</div>`;

// Slack Block Kit
const slackBlocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: `🎯 ${jobs.length} new internship${jobs.length > 1 ? 's' : ''} found`, emoji: true }
  },
  { type: 'divider' },
  ...jobs.map(j => ({
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*<${j.link}|${j.title}>*\n${j.company} · ${j.location}\n💰 ${j.stipend} · _${j.source}_`
    }
  })),
  { type: 'divider' },
  {
    type: 'context',
    elements: [{ type: 'mrkdwn', text: 'InternHunt · runs every 6h' }]
  }
];

return [{ json: { emailHtml, slackBlocks: JSON.stringify({ blocks: slackBlocks }), count: jobs.length } }];

// ── Error reporter ───────────────────────────────────────
const err = $input.first().json;
return [{
  json: {
    subject: '⚠️ InternHunt workflow error',
    body: `<b>Error in node:</b> ${err.node?.name || 'unknown'}<br><b>Message:</b> ${err.message || JSON.stringify(err)}`
  }
}];
